// frontend/src/components/MapSidebar.js
import React from 'react';
import mapImage from '../assets/maharashtra-map.png'; // Place your PNG in src/assets

const MapSidebar = () => {
  return (
    <div className="map-sidebar" style={{ width: '30%', float: 'left' }}>
      <img src={mapImage} alt="Maharashtra Map" style={{ width: '100%' }} />
    </div>
  );
};

export default MapSidebar;
